import React from 'react';

interface LogoProps {
  style: string;
  imgSrc: string;
  width: number;
  height: number;
}

const Logo: React.FC<LogoProps> = ({}) => {
  return (
    <a href="/">
      <img className={style} src={imgSrc} alt="logo" />
    </a>
  );
};

export default Logo;


